/**
 * Button — CSS-only button with CVA variants. No motion dependency.
 *
 * A zero-dependency button that composes `class-variance-authority` for
 * variants (`default`, `destructive`, `outline`, `secondary`, `ghost`,
 * `link`) and sizes (`sm`, `md`, `lg`, `icon`). Pass `asChild` to render
 * the styles on any child (e.g. a `next/link` `<a>`) via the `Slot`
 * primitive. An `IconButton` convenience wrapper is also exported with
 * `size="icon"` and a rounded-full default.
 *
 * Anatomy:
 * ```tsx
 * <Button variant="default" size="md">Save</Button>
 * <Button variant="outline" size="sm">Cancel</Button>
 * <Button asChild><Link href="/x">Go</Link></Button>
 * <IconButton aria-label="Add"><PlusIcon /></IconButton>
 * ```
 *
 * @package    @edbn/ui
 * @version    0.3.0
 * @since      0.1.0
 * @brand      edbn/ui — https://ui.edbn.me
 * @docs       https://ui.edbn.me/docs/components/button
 * @registryDescription Static button component with CSS transitions only. No motion dependency required.
 */

"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";
import { Slot } from "@/lib/slot";

// ---- VARIANTS ---------------------------------------------------------------

const buttonVariants = cva(
  [
    "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium",
    "transition-colors duration-150 motion-reduce:transition-none",
    "focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ring",
    "disabled:pointer-events-none disabled:opacity-50",
    "select-none cursor-pointer",
    "[&_svg]:pointer-events-none [&_svg]:shrink-0",
  ],
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground hover:bg-primary/90 active:bg-primary/80",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90 active:bg-destructive/80",
        outline:
          "border border-border bg-background text-foreground hover:bg-muted active:bg-muted/80",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80 active:bg-secondary/70",
        ghost: "text-foreground hover:bg-muted active:bg-muted/80",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        sm: "h-8 rounded-md px-3 text-xs [&_svg]:size-3.5",
        md: "h-9 px-4 py-2 [&_svg]:size-4",
        lg: "h-10 rounded-md px-6 text-base [&_svg]:size-5",
        icon: "h-9 w-9 [&_svg]:size-4",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
);

// ---- BUTTON -----------------------------------------------------------------

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  /** Render the button styles onto the single child element. */
  asChild?: boolean;
}

/**
 * Themed button with CVA variants. Pass `asChild` to style any child
 * element (e.g. a link) without adding an extra DOM node.
 *
 * @since 0.1.0
 */
function Button({
  className,
  variant,
  size,
  asChild,
  ...props
}: ButtonProps) {
  const Comp = asChild ? Slot : "button";
  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  );
}
Button.displayName = "Button";

// ---- ICON BUTTON ------------------------------------------------------------

export type IconButtonProps = ButtonProps;

/**
 * Convenience wrapper around `Button` with `size="icon"` and a
 * rounded-full default. Always pass an `aria-label`.
 *
 * @since 0.1.0
 */
function IconButton({ className, size = "icon", ...props }: IconButtonProps) {
  return (
    <Button
      data-slot="icon-button"
      size={size}
      className={cn("rounded-full", className)}
      {...props}
    />
  );
}
IconButton.displayName = "IconButton";

// ---- EXPORTS ----------------------------------------------------------------

export { Button, IconButton, buttonVariants };

/**
 * Primitive Component Adapter Layer
 *
 * Re-exports headless UI primitives used by edbn-ui components.
 * Components import from this file instead of directly from provider packages.
 *
 * Base UI (@base-ui/react) is the primary primitive provider.
 * Slot is vendored locally (oss/lib/slot.ts).
 *
 * @packageDocumentation
 * @registryDescription Re-exports of headless UI primitives (Base UI, Slot) used across edbn-ui components.
 */

// ---- SLOT (Polymorphic rendering) -------------------------------------------

export { Slot } from "./slot";

// ---- AVATAR (Base UI) -------------------------------------------------------

export { Avatar as AvatarPrimitive } from "@base-ui/react/avatar";

// ---- BASE UI PRIMITIVES -----------------------------------------------------

export { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
export { AlertDialog as AlertDialogPrimitive } from "@base-ui/react/alert-dialog";
export { Checkbox as CheckboxPrimitive } from "@base-ui/react/checkbox";
export { CheckboxGroup as CheckboxGroupPrimitive } from "@base-ui/react/checkbox-group";
export { Collapsible as CollapsiblePrimitive } from "@base-ui/react/collapsible";
export { Dialog as DialogPrimitive } from "@base-ui/react/dialog";
export { Field as FieldPrimitive } from "@base-ui/react/field";
export { Fieldset as FieldsetPrimitive } from "@base-ui/react/fieldset";
export { Form as FormPrimitive } from "@base-ui/react/form";
export { Input as InputPrimitive } from "@base-ui/react/input";
export { Menu as MenuPrimitive } from "@base-ui/react/menu";
export { NumberField as NumberFieldPrimitive } from "@base-ui/react/number-field";
export { Popover as PopoverPrimitive } from "@base-ui/react/popover";
export { PreviewCard as PreviewCardPrimitive } from "@base-ui/react/preview-card";
export { Progress as ProgressPrimitive } from "@base-ui/react/progress";
export { Radio as RadioPrimitive } from "@base-ui/react/radio";
export { RadioGroup as RadioGroupPrimitive } from "@base-ui/react/radio-group";
export { ScrollArea as ScrollAreaPrimitive } from "@base-ui/react/scroll-area";
export { Select as SelectPrimitive } from "@base-ui/react/select";
export { Separator as SeparatorPrimitive } from "@base-ui/react/separator";
export { Slider as SliderPrimitive } from "@base-ui/react/slider";
export { Switch as SwitchPrimitive } from "@base-ui/react/switch";
export { Tabs as TabsPrimitive } from "@base-ui/react/tabs";
export { Toast as ToastPrimitive } from "@base-ui/react/toast";
export { Toggle as TogglePrimitive } from "@base-ui/react/toggle";
export { ToggleGroup as ToggleGroupPrimitive } from "@base-ui/react/toggle-group";
export { Toolbar as ToolbarPrimitive } from "@base-ui/react/toolbar";
export { Tooltip as TooltipPrimitive } from "@base-ui/react/tooltip";

/**
 * Slot Component - Polymorphic Rendering
 *
 * A vendored Slot implementation for the `asChild` prop pattern.
 * Merges props, classNames, styles, event handlers, and refs onto a single child element.
 *
 * Based on shadcn/ui Slot pattern (MIT licensed), simplified for our use cases:
 * - Conditional component pattern: `const Comp = asChild ? Slot : "button"`
 * - Early-return pattern: `if (asChild) return <Slot>{children}</Slot>`
 *
 * @packageDocumentation
 * @registryPartOf primitives
 */

import * as React from "react";

type AnyProps = Record<string, unknown>;

type AnyFn = (...args: unknown[]) => unknown;

function mergeRefs<T>(
  ...refs: Array<React.Ref<T> | undefined>
): React.RefCallback<T> {
  return (value) => {
    refs.forEach((ref) => {
      if (typeof ref === "function") {
        ref(value);
      } else if (ref != null) {
        (ref as React.MutableRefObject<T | null>).current = value;
      }
    });
  };
}

function mergeProps(slotProps: AnyProps, childProps: AnyProps): AnyProps {
  const result: AnyProps = { ...slotProps };

  for (const key in childProps) {
    const slotValue = slotProps[key];
    const childValue = childProps[key];

    const isHandler = /^on[A-Z]/.test(key);

    if (isHandler) {
      if (slotValue && childValue) {
        result[key] = (...args: unknown[]) => {
          (childValue as AnyFn)(...args);
          (slotValue as AnyFn)(...args);
        };
      } else {
        result[key] = childValue || slotValue;
      }
    } else if (key === "style") {
      result[key] = { ...(slotValue as object), ...(childValue as object) };
    } else if (key === "className") {
      result[key] = [slotValue, childValue].filter(Boolean).join(" ");
    } else {
      result[key] = childValue !== undefined ? childValue : slotValue;
    }
  }

  return result;
}

interface SlotProps extends React.HTMLAttributes<HTMLElement> {
  children?: React.ReactNode;
}

const Slot = React.forwardRef<HTMLElement, SlotProps>((props, forwardedRef) => {
  const { children, ...slotProps } = props;

  if (!React.isValidElement(children)) {
    if (
      process.env.NODE_ENV !== "production" &&
      children !== null &&
      children !== undefined
    ) {
      console.warn("Slot: Expected a single React element child");
    }
    return null;
  }

  const childElement = children as React.ReactElement<
    AnyProps & { ref?: React.Ref<unknown> }
  >;
  const mergedProps = mergeProps(slotProps, childElement.props);

  const childRef = (childElement as { ref?: React.Ref<unknown> }).ref;

  return React.cloneElement(childElement, {
    ...mergedProps,
    ref: forwardedRef
      ? mergeRefs(forwardedRef, childRef as React.Ref<HTMLElement>)
      : (childRef as React.Ref<HTMLElement>),
  });
});

Slot.displayName = "Slot";

export { Slot, mergeRefs, mergeProps };
export type { SlotProps };
